import base64
import cv2
import numpy as np
from math import radians, cos, sin, asin, sqrt
from skimage.metrics import structural_similarity as ssim

# --- 1. GEOGRAPHIC DISTANCE CHECK ---
def calculate_distance(loc1_str, loc2_str):
    """Calculates meters between two 'lat, long' strings"""
    try:
        lat1, lon1 = map(float, loc1_str.split(','))
        lat2, lon2 = map(float, loc2_str.split(','))
        
        R = 6371000  # Radius of Earth in meters
        dLat, dLon = radians(lat2 - lat1), radians(lon2 - lon1)
        a = sin(dLat/2)**2 + cos(radians(lat1)) * cos(radians(lat2)) * sin(dLon/2)**2
        return 2 * R * asin(sqrt(a))
    except:
        return float('inf')

# --- 2. IMAGE PROCESSING ---
def decode_image(base64_str):
    """Converts Base64 string to an OpenCV image"""
    if "," in base64_str:
        base64_str = base64_str.split(",")[1]
    
    img_data = base64.b64decode(base64_str)
    nparr = np.frombuffer(img_data, np.uint8)
    return cv2.imdecode(nparr, cv2.IMREAD_COLOR)

def compare_images(img1, img2):
    """Returns a similarity score from -1 to 1 (1 is identical)"""
    # Resize to same dimensions for comparison
    img1 = cv2.resize(img1, (400, 400))
    img2 = cv2.resize(img2, (400, 400))
    
    # Convert to grayscale
    gray1 = cv2.cvtColor(img1, cv2.COLOR_BGR2GRAY)
    gray2 = cv2.cvtColor(img2, cv2.COLOR_BGR2GRAY)
    
    # Compute Structural Similarity Index (SSIM)
    score, _ = ssim(gray1, gray2, full=True)
    return score

# --- 3. THE FINAL LOGIC ---
def verify_incident(data):
    # Get values from your JSON structure
    user_loc = data.get("location")
    admin_loc = data.get("resolution_proof", {}).get("location", user_loc) # Fallback if admin loc missing
    
    user_img_str = data.get("image_proof")
    admin_img_str = data.get("resolution_proof", {}).get("images", [None])[0]

    if not user_img_str or not admin_img_str:
        return "Error: Missing image data."

    # Execute Checks
    distance = calculate_distance(user_loc, admin_loc)
    img_user = decode_image(user_img_str)
    img_admin = decode_image(admin_img_str)
    similarity = compare_images(img_user, img_admin)

    # Result logic
    is_location_ok = distance < 50  # Within 50 meters
    # A score > 0.4 usually means same scene but with changes (like a pothole being filled!)
    # 1.0 would mean it's the exact same photo (possible cheating)
    is_visual_ok = 0.35 < similarity < 0.98 

    print(f"Distance: {distance:.2f}m")
    print(f"Similarity Score: {similarity:.4f}")

    if is_location_ok and is_visual_ok:
        print("✅ VERIFIED: Pothole likely resolved at correct location.")
    elif not is_location_ok:
        print("❌ REJECTED: Admin is too far from the reported location.")
    else:
        print("⚠️ FLAG: Location matches, but visual proof is unclear. Manual review needed.")

